import {
    ActorPF2e,
    ActorSheetOptions,
    ActorSheetPF2e,
    belongToPartyAlliance,
    CharacterPF2e,
    CharacterSheetPF2e,
    createHTMLElement,
    createToggleHook,
    createToggleWrapper,
    CreaturePF2e,
    CreatureSheetData,
    FamiliarPF2e,
    FamiliarSheetPF2e,
    FeatPF2e,
    htmlQuery,
    isInstanceOf,
    localeCompare,
    NPCSheetPF2e,
    PhysicalItemPF2e,
    PhysicalItemType,
    R,
    renderActorSheets,
    renderCharacterSheets,
    SpellcastingEntryPF2e,
    SpellCollection,
    SpellPreparationSheet,
    SYSTEM,
    toggleHooksAndWrappers,
} from "foundry-helpers";
import { ModuleTool, ToolSettingsList } from "module-tool";
import { betterMerchantTool } from "tools";
import { FeatRetrainPopup } from ".";

class BetterSheetTool extends ModuleTool<ToolSettings> {
    #partyAsObservedHooks = [
        createToggleWrapper(
            "OVERRIDE",
            "CONFIG.Actor.sheetClasses.character['pf2e.CharacterSheetPF2e'].cls.prototype.template",
            this.#characterSheetPF2eTemplate,
            { context: this },
        ),
        createToggleWrapper(
            "OVERRIDE",
            "CONFIG.Actor.sheetClasses.npc['pf2e.NPCSheetPF2e'].cls.prototype.template",
            this.#npcSheetPF2eTemplate,
            { context: this },
        ),
        createToggleWrapper(
            "WRAPPER",
            "CONFIG.Actor.sheetClasses.familiar['pf2e.FamiliarSheetPF2e'].cls.prototype.getData",
            this.#familiarSheetPF2eGetData,
            { context: this },
        ),
    ];

    #retrainFeatsHook = createToggleHook("renderCharacterSheetPF2e", this.#onRenderCharacterSheetPF2e.bind(this));

    #showPlayersHook = createToggleHook("renderActorSheetPF2e", this.#showPlayersOnRender.bind(this));

    #sortListHooks = [
        createToggleHook("renderActorSheetPF2e", this.#sortListOnRender.bind(this)),
        createToggleHook("renderSpellPreparationSheet", this.#addSpellbookSortList.bind(this)),
    ];

    get key(): "betterSheet" {
        return "betterSheet";
    }

    get settingsSchema(): ToolSettingsList<ToolSettings> {
        return [
            {
                key: "partyAsObserved",
                type: Boolean,
                default: false,
                scope: "world",
                onChange: (value: boolean) => {
                    toggleHooksAndWrappers(this.#partyAsObservedHooks, !game.user.isGM && value);
                    renderActorSheets();
                },
            },
            {
                key: "showPlayers",
                type: Boolean,
                default: false,
                scope: "user",
                gmOnly: true,
                onChange: (value: boolean) => {
                    if (game.user.isGM) {
                        this.#showPlayersHook.toggle(value);
                        renderActorSheets();
                    }
                },
            },
            {
                key: "sortList",
                type: Boolean,
                default: false,
                scope: "user",
                onChange: (value: boolean) => {
                    toggleHooksAndWrappers(this.#sortListHooks, value);
                    renderActorSheets();
                },
            },
            {
                key: "retrainFeats",
                type: Boolean,
                default: false,
                scope: "user",
                onChange: (value: boolean) => {
                    this.#retrainFeatsHook.toggle(value);
                    renderCharacterSheets();
                },
            },
        ];
    }

    init(isGM: boolean): void {
        this.#retrainFeatsHook.toggle(this.settings.retrainFeats);
        this.#showPlayersHook.toggle(isGM && this.settings.showPlayers);
        toggleHooksAndWrappers(this.#sortListHooks, this.settings.sortList);
    }

    ready(isGM: boolean): void {
        toggleHooksAndWrappers(this.#partyAsObservedHooks, !isGM && this.settings.partyAsObserved);
    }

    #onRenderCharacterSheetPF2e(sheet: CharacterSheetPF2e<CharacterPF2e>, $html: JQuery) {
        if (!sheet.isEditable) return;

        const html = $html[0];
        const tab = htmlQuery(html, `.tab[data-tab="feats"]`);
        if (!tab) return;

        const actor = sheet.actor;
        const sections = tab.querySelectorAll<HTMLElement>(`.feat-section`);

        for (const section of sections) {
            const category = section.dataset.groupId as string;
            const selector = R.isIncludedIn(category, ["ancestryfeature", "classfeature"])
                ? ".nested-items [data-item-id]"
                : "[data-item-id]";

            const featRows = section.querySelectorAll<HTMLElement>(selector);

            for (const featRow of featRows) {
                const controls = htmlQuery(featRow, ".item-controls");
                const btn = createHTMLElement("a", {
                    classes: ["pf2e-toobelt-retrain-feat"],
                    content: `<i class="fa-solid fa-fw fa-arrows-repeat"></i>`,
                    dataset: {
                        tooltip: this.localize.path("retrain.title"),
                    },
                });

                btn.addEventListener("click", (event) => {
                    event.preventDefault();
                    event.stopPropagation();

                    const currentFeat = actor.items.get<FeatPF2e<CharacterPF2e>>(featRow.dataset.itemId ?? "");
                    if (!currentFeat) return;

                    new FeatRetrainPopup(this, currentFeat, category).render(true);
                });

                controls?.prepend(btn);
            }
        }
    }

    #npcSheetPF2eTemplate(sheet: NPCSheetPF2e): string {
        if (sheet.isLootSheet) {
            return SYSTEM.relativePath("templates/actors/npc/loot-sheet.hbs");
        } else if (sheet.actor.limited && !belongToPartyAlliance(sheet.actor)) {
            return SYSTEM.relativePath("templates/actors/limited/npc-sheet.hbs");
        }
        return SYSTEM.relativePath("templates/actors/npc/sheet.hbs");
    }

    #characterSheetPF2eTemplate(sheet: CharacterSheetPF2e<CharacterPF2e>): string {
        const actor = sheet.actor;
        const template = actor.limited && !belongToPartyAlliance(actor) ? "limited" : "sheet";

        return SYSTEM.relativePath(`templates/actors/character/${template}.hbs`);
    }

    async #familiarSheetPF2eGetData(
        sheet: FamiliarSheetPF2e<FamiliarPF2e>,
        wrapped: libWrapper.RegisterCallback,
        options?: ActorSheetOptions,
    ): Promise<CreatureSheetData<FamiliarPF2e>> {
        const data = (await wrapped(options)) as CreatureSheetData<FamiliarPF2e>;

        if (belongToPartyAlliance(sheet.actor)) {
            data.limited = false;
            data.document = data.document.clone();

            Object.defineProperty(data.document, "limited", {
                get() {
                    return false;
                },
            });
        }

        return data;
    }

    #showPlayersOnRender(sheet: ActorSheetPF2e<ActorPF2e>, $html: JQuery) {
        const html = $html[0];
        const imgPanel = htmlQuery(html, ".image-container");
        if (!imgPanel) return;

        const actor = sheet.actor;
        const btn = createHTMLElement("a", {
            classes: ["hover-icon", "show-players"],
            content: `<i class="fa-fw fa-solid fa-eye"></i></a>`,
            dataset: {
                tooltip: "JOURNAL.ActionShow",
            },
        });

        btn.addEventListener("click", () => {
            game.socket.emit("shareImage", {
                image: actor.img,
                title: actor.name,
                uuid: actor.uuid,
            });

            ui.notifications.info("JOURNAL.ActionShowSuccess", {
                format: { mode: "image", title: actor.name, which: "all" },
            });
        });

        imgPanel.appendChild(btn);
    }

    #sortListOnRender(sheet: ActorSheetPF2e<ActorPF2e>, $html: JQuery) {
        if (!sheet.isEditable) return;

        const html = $html[0];
        const actor = sheet.actor;

        this.#addActionsSortList(html, actor);
        this.#addCraftingSortList(html, actor);
        this.#addInventorySortList(html, actor);
        this.#addSpellcastingSortList(html, actor);
    }

    #createSortBtn(disabled: boolean, label = "tooltip") {
        const classes = ["with-sort-btn"];

        if (disabled) {
            classes.push("disabled");
        }

        return createHTMLElement("a", {
            classes,
            content: `<i class="fa-solid fa-arrow-up-a-z"></i>`,
            dataset: {
                tooltip: this.localize.path(`sortList.sheet.${label}`),
            },
        });
    }

    async #sortCollectionSpells(collection: SpellCollection<CreaturePF2e>) {
        const updates = R.pipe(
            collection.contents,
            R.groupBy((spell) => (spell.isCantrip ? 0 : spell.rank)),
            R.values(),
            R.flatMap((group) => {
                group.sort((a, b) => a._source.name.localeCompare(b._source.name));
                return group;
            }),
            R.map((item, index) => {
                return { _id: item.id, sort: 50000 * index };
            }),
        );

        await collection.actor.updateEmbeddedDocuments("Item", updates);
    }

    async #sortPrepCollection(entry: SpellcastingEntryPF2e<CreaturePF2e>) {
        const actor = entry.actor;

        const updates = R.mapValues(entry.system.slots, (slot) => {
            return {
                prepared: slot.prepared.sort((a, b) => {
                    const spellA = a.id ? actor.items.get(a.id) : null;
                    const spellB = b.id ? actor.items.get(b.id) : null;

                    if (!spellA && !spellB) return 0;
                    if (!spellA) return 1;
                    if (!spellB) return -1;

                    return spellA.name.localeCompare(spellB.name);
                }),
            };
        });

        await entry.update({ "system.slots": updates });
    }

    #addSpellbookSortList(sheet: SpellPreparationSheet<CreaturePF2e>, $html: JQuery) {
        if (!sheet.isEditable) return;

        const html = $html[0];
        const actor = sheet.actor;
        const collectionId = htmlQuery(html, `[data-entry-id]`)?.dataset.entryId;
        const collection = actor.spellcasting.collections.get(collectionId ?? "");
        if (!collection) return;

        const name = htmlQuery(html, ".sheet-header h1");
        const disabled = collectionIsDisabled(collection);
        const btn = this.#createSortBtn(disabled);

        name?.classList.add("with-sort");
        name?.prepend(btn);

        if (disabled) return;

        btn.addEventListener("click", async () => {
            if (collection) {
                await this.#sortCollectionSpells(collection);
            }
        });
    }

    #addSpellcastingSortList(html: HTMLElement, actor: ActorPF2e) {
        if (!actor.isOfType("character")) return;

        const spellcasting = htmlQuery(html, `.tab[data-tab="spellcasting"] .known-spells`);
        const sections = spellcasting?.querySelectorAll<HTMLElement>(".spellcasting-entry");

        for (const section of sections ?? []) {
            const collectionId = section.dataset.itemId;
            const collection = actor.spellcasting.collections.get(collectionId ?? "");
            if (!collection) continue;

            const entry = collection.entry as unknown as SpellcastingEntryPF2e<CreaturePF2e>;
            if (!isInstanceOf(entry, "SpellcastingEntryPF2e")) continue;

            const name = htmlQuery(section, ".action-header .item-name");

            const disabled = entry.isFlexible
                ? true
                : entry.isPrepared
                  ? R.values(entry.system.slots).every(({ prepared }) => {
                        return prepared.filter((slot) => slot.id).length < 2;
                    })
                  : collectionIsDisabled(collection);

            const btn = this.#createSortBtn(disabled);

            name?.classList.add("with-sort");
            name?.prepend(btn);

            if (disabled) continue;

            btn.addEventListener("click", async () => {
                if (entry.isPrepared) {
                    await this.#sortPrepCollection(entry);
                } else {
                    await this.#sortCollectionSpells(collection);
                }
            });
        }
    }

    #addActionsSortList(html: HTMLElement, actor: ActorPF2e) {
        if (!actor.isOfType("npc")) return;

        const actionsTab = htmlQuery(html, `.tab[data-tab="main"]`);

        for (const type of ["action", "passive"] as const) {
            const section = htmlQuery(actionsTab, `.section-container.${type}s`);
            const name = htmlQuery(section, ".section-header h4");
            const disabled = (htmlQuery(section, ".item-list")?.children.length ?? 0) < 2;
            const btn = this.#createSortBtn(disabled);

            name?.prepend(btn);

            if (disabled) continue;

            btn.addEventListener("click", async () => {
                const updates = R.pipe(
                    actor.itemTypes.action,
                    R.filter((item) => (type === "action" ? !!item.actionCost : !item.actionCost)),
                    R.sort((a, b) => a.name.localeCompare(b.name)),
                    R.map((item, index) => {
                        return { _id: item.id, sort: 50000 * index };
                    }),
                );

                await actor.updateEmbeddedDocuments("Item", updates);
            });
        }
    }

    #addCraftingSortList(html: HTMLElement, actor: ActorPF2e) {
        if (!actor.isOfType("character")) return;

        const craftingTab = htmlQuery(html, `.tab[data-tab="crafting"]`);
        if (!craftingTab) return;

        this.#addCraftingFormulasSort(craftingTab, actor);
        this.#addCraftingEntriesSort(craftingTab, actor);
    }

    #addCraftingEntriesSort(html: HTMLElement, actor: CharacterPF2e) {
        const entries = html.querySelectorAll<HTMLElement>(".crafting-entry-list .crafting-entry[data-ability]");

        for (const entry of entries) {
            const header = htmlQuery(entry, ".action-header .item-name");
            if (!header) continue;

            const ability = actor.crafting.abilities.get(entry.dataset.ability ?? "");
            if (!ability) continue;

            const disabled = ability.preparedFormulaData.length === 0;
            const btn = this.#createSortBtn(disabled);

            header.prepend(btn);

            if (disabled) continue;

            btn.addEventListener("click", async () => {
                const formulas = R.sortBy(
                    ability.preparedFormulaData,
                    ({ uuid }) => fromUuidSync(uuid, { strict: false })?.name ?? "",
                );
                ability.updateFormulas(formulas);
            });
        }
    }

    #addCraftingFormulasSort(html: HTMLElement, actor: CharacterPF2e) {
        const crafting = htmlQuery(html, `.known-formulas`);
        const header = htmlQuery(crafting, ":scope > header");
        const disabled = actor.system.crafting.formulas.length === 0;
        const btn = this.#createSortBtn(disabled);

        header?.prepend(btn);

        if (disabled) return;

        btn.addEventListener("click", async () => {
            const formulas = R.sortBy(
                actor.system.crafting.formulas,
                ({ uuid }) => fromUuidSync(uuid, { strict: false })?.name ?? "",
            );
            await actor.update({ "system.crafting.formulas": formulas });
        });
    }

    #addInventorySortList(html: HTMLElement, actor: ActorPF2e) {
        const isLoot = actor.isOfType("loot");
        const inventorySelector = isLoot ? ".sheet-body.inventory" : `.tab[data-tab="inventory"]`;
        const inventory = htmlQuery(html, inventorySelector + " .inventory-list");
        if (!inventory) return;

        const headers = inventory.querySelectorAll(":scope > header");

        for (const header of headers) {
            const itemsList = header.nextElementSibling as HTMLElement | undefined;
            if (!itemsList || !itemsList.classList.contains("items")) continue;

            const types = R.split(itemsList.dataset.itemTypes ?? "", ",") as PhysicalItemType[];
            const hasContainer = !!types.findSplice((type) => type === "backpack");
            const name = htmlQuery(header, ".item-name");
            const disabled = hasContainer
                ? actor.itemTypes.backpack.every((container) => container.contents.size < 2)
                : itemsList.children.length < 2;
            const btn = this.#createSortBtn(disabled, hasContainer ? "container" : undefined);

            name?.prepend(btn);

            if (disabled) continue;

            btn.addEventListener("click", async () => {
                if (isLoot && header.classList.contains("services")) {
                    const services = betterMerchantTool.getServices(actor);
                    services.sort((a, b) => localeCompare(a.name || a.id, b.name || a.id));
                    return await betterMerchantTool.setServives(actor, services);
                }

                const sortItems = (a: PhysicalItemPF2e, b: PhysicalItemPF2e): number => {
                    return a._source.name.localeCompare(b._source.name);
                };

                const mapItems = (item: PhysicalItemPF2e, index: number) => {
                    return { _id: item.id, sort: 50000 * index };
                };

                const updates = R.pipe(
                    types,
                    R.map((type) => type in actor.itemTypes && actor.itemTypes[type]),
                    R.filter(R.isTruthy),
                    R.flat(),
                    R.filter((item) => !item.isInContainer),
                    R.sort(sortItems),
                    R.map(mapItems),
                );

                if (hasContainer) {
                    for (const container of actor.itemTypes.backpack) {
                        updates.push(...R.pipe(container.contents.contents, R.sort(sortItems), R.map(mapItems)));
                    }
                }

                await actor.updateEmbeddedDocuments("Item", updates);
            });
        }
    }
}

function collectionIsDisabled(collection: SpellCollection<CreaturePF2e>): boolean {
    const groups = R.pipe(
        collection.contents,
        R.groupBy((spell) => (spell.isCantrip ? 0 : spell.rank)),
        R.values(),
    );

    return groups.every((spells) => spells.length < 2);
}

type ToolSettings = {
    partyAsObserved: boolean;
    retrainFeats: boolean;
    scribble: boolean;
    showPlayers: boolean;
    sortList: boolean;
};

export { BetterSheetTool };
